align*
 1 - x &= 1 - (1 - x^{2}{2} + x^{4}{24} - )
 = x^{2}{2} - x^{4}{24} + \\[4pt]
 x\sin x &= x\left(x - \frac{x^{3}}{6} + \cdots\right)
 = x^{2} - \frac{x^{4}}{6} + \cdots
\end{align*}
Therefore,
\[
 \frac{1 - \cos x}{x\sin x}
 = \frac{\frac{x^{2}}{2} - \frac{x^{4}}{24} + \cdots}{x^{2} - \frac{x^{4}}{6} + \cdots}
 = \frac{\frac{1}{2} - \frac{x^{2}}{24} + \cdots}{1 - \frac{x^{2}}{6} + \cdots}
 \to \frac{1/2}{1} = \frac{1}{2}.
\]
